def engagement_report(spec: dict) -> str:
    """Rank users by total likes received on their posts: 'name=likes' comma-joined, likes desc then name."""
    users = sorted(set(spec["users"]))
    per_post = {}
    for l in spec["likes"]:
        if l[0] in users:
