        if r[0] in pnodes and r[1] in pnodes { pnodes[r[1]] +>:Repost:+> pnodes[r[0]]; }
    }
    start: str = str(spec["start"]);
    if start not in pnodes { return ""; }
    w = pnodes[start] spawn ChainWalk();
    return ">".join(w.path);
}

